        #       "event_type": "cancel",
        #       "order_type": "limit",
        #       "order_status": "cancelled",
        #       "stop_price": null,
        #       "stop_parent_order_id": null,
        #       "reduce_only": False,
        #       "created_at": 1759224895038
        #     },
        #     {
        #       "history_id": 641452513,
        #       "order_id": 315992721,
        #       "client_order_id": "ade1aa6...",
        #       "symbol": "XPL",
        #       "side": "ask",
        #       "price": "1.0865",
        #       "initial_amount": "984",
        #       "filled_amount": "0",
        #       "cancelled_amount": "0",
